PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?eurCount ?czkCount ?ratio WHERE {
  {
    SELECT ( COUNT( DISTINCT ?custE ) AS ?eurCount ) WHERE {
      ?custE <http://debit_card_specializing.org/customers#Currency> "EUR" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?custC ) AS ?czkCount ) WHERE {
      ?custC <http://debit_card_specializing.org/customers#Currency> "CZK" .
    }
  }
  BIND( xsd:double ( ?eurCount ) / xsd:double ( ?czkCount ) AS ?ratio )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?customer ?customerLabel ( SUM( xsd:decimal ( ?cons ) ) AS ?total ) WHERE {
  ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?custID ; <http://debit_card_specializing.org/yearmonth#Date> ?date ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
  ?customer <http://debit_card_specializing.org/customers#CustomerID> ?custID ; <http://debit_card_specializing.org/customers#Segment> ?segment .
  OPTIONAL {
    ?customer rdfs:label ?customerLabel
  }
  FILTER ( STR( ?segment ) = "LAM" ) FILTER ( SUBSTR( STR( ?date ) , 1 , 4 ) = "2012" )
}
GROUP BY ?customer ?customerLabel
ORDER BY ?total
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?czkSum ?eurSum ?difference WHERE {
  {
    SELECT ( SUM( xsd:decimal ( ?cons ) ) AS ?czkSum ) WHERE {
      ?ym <http://debit_card_specializing.org/yearmonth#Date> ?date ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons ; <http://debit_card_specializing.org/yearmonth#ref-CustomerID> ?cust .
      ?cust <http://debit_card_specializing.org/customers#Currency> "CZK" .
      FILTER ( SUBSTR( STR( ?date ) , 1 , 4 ) = "2012" )
    }
  }
  {
    SELECT ( SUM( xsd:decimal ( ?cons2 ) ) AS ?eurSum ) WHERE {
      ?ym2 <http://debit_card_specializing.org/yearmonth#Date> ?date2 ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons2 ; <http://debit_card_specializing.org/yearmonth#ref-CustomerID> ?cust2 .
      ?cust2 <http://debit_card_specializing.org/customers#Currency> "EUR" .
      FILTER ( SUBSTR( STR( ?date2 ) , 1 , 4 ) = "2012" )
    }
  }
  BIND( ( ?czkSum - ?eurSum ) AS ?difference )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?SME_min ?LAM_min ?KAM_min ( ?SME_min - ?LAM_min AS ?SME_minus_LAM ) ( ?LAM_min - ?KAM_min AS ?LAM_minus_KAM ) ( ?KAM_min - ?SME_min AS ?KAM_minus_SME ) WHERE {
  {
    SELECT ( MIN( ?annualTotal ) AS ?SME_min ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( xsd:decimal ( ?cons ) ) AS ?annualTotal ) WHERE {
          ?ym a ?y .
          FILTER ( CONTAINS( STR( ?ym ) , "yearmonth" ) ) ?ym <http://debit_card_specializing.org/yearmonth#Date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) ) ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?cid .
          ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
          ?cust <http://debit_card_specializing.org/customers#CustomerID> ?cid .
          ?cust <http://debit_card_specializing.org/customers#Segment> ?segment .
        }
        GROUP BY ?cust ?segment
      }
      FILTER ( ?segment = "SME" )
    }
  }
  {
    SELECT ( MIN( ?annualTotal ) AS ?LAM_min ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( xsd:decimal ( ?cons ) ) AS ?annualTotal ) WHERE {
          ?ym a ?y .
          FILTER ( CONTAINS( STR( ?ym ) , "yearmonth" ) ) ?ym <http://debit_card_specializing.org/yearmonth#Date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) ) ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?cid .
          ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
          ?cust <http://debit_card_specializing.org/customers#CustomerID> ?cid .
          ?cust <http://debit_card_specializing.org/customers#Segment> ?segment .
        }
        GROUP BY ?cust ?segment
      }
      FILTER ( ?segment = "LAM" )
    }
  }
  {
    SELECT ( MIN( ?annualTotal ) AS ?KAM_min ) WHERE {
      {
        SELECT ?cust ?segment ( SUM( xsd:decimal ( ?cons ) ) AS ?annualTotal ) WHERE {
          ?ym a ?y .
          FILTER ( CONTAINS( STR( ?ym ) , "yearmonth" ) ) ?ym <http://debit_card_specializing.org/yearmonth#Date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) ) ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?cid .
          ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
          ?cust <http://debit_card_specializing.org/customers#CustomerID> ?cid .
          ?cust <http://debit_card_specializing.org/customers#Segment> ?segment .
        }
        GROUP BY ?cust ?segment
      }
      FILTER ( ?segment = "KAM" )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?segment ?sum2012 ?sum2013 ?increase ?pctIncrease WHERE {
  {
    SELECT ?segment ( SUM( IF( ?year = "2012" , xsd:decimal ( ?cons ) , 0 ) ) AS ?sum2012 ) ( SUM( IF( ?year = "2013" , xsd:decimal ( ?cons ) , 0 ) ) AS ?sum2013 ) WHERE {
      ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?cid ; <http://debit_card_specializing.org/yearmonth#Date> ?ymDate ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
      ?cust <http://debit_card_specializing.org/customers#CustomerID> ?cid ; <http://debit_card_specializing.org/customers#Segment> ?segment ; <http://debit_card_specializing.org/customers#Currency> ?currency .
      BIND( STR( ?ymDate ) AS ?ymstr ) BIND( SUBSTR( ?ymstr , 1 , 4 ) AS ?year ) FILTER ( ?segment IN ( "SME" , "LAM" , "KAM" ) ) FILTER ( STR( ?currency ) = "EUR" )
    }
    GROUP BY ?segment
  }
  BIND( ( ?sum2013 - ?sum2012 ) AS ?increase ) BIND( ( ?increase / ?sum2013 ) * 100 AS ?pctIncrease )
}
ORDER BY DESC ( ?pctIncrease )

PREFIX gs: <http://debit_card_specializing.org/gasstations#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?cze_count ?svk_count ?difference WHERE {
  {
    SELECT ( COUNT( ?s1 ) AS ?cze_count ) WHERE {
      ?s1 gs:Country "CZE" .
      ?s1 gs:Segment "Discount" .
    }
  }
  {
    SELECT ( COUNT( ?s2 ) AS ?svk_count ) WHERE {
      ?s2 gs:Country "SVK" .
      ?s2 gs:Segment "Discount" .
    }
  }
  BIND( xsd:integer ( ?cze_count ) - xsd:integer ( ?svk_count ) AS ?difference )
}

SELECT ( SUM( IF( ?currency = "CZK" , 1 , 0 ) ) AS ?countCZK ) ( SUM( IF( ?currency = "EUR" , 1 , 0 ) ) AS ?countEUR ) ( ( SUM( IF( ?currency = "CZK" , 1 , 0 ) ) - SUM( IF( ?currency = "EUR" , 1 , 0 ) ) ) AS ?difference ) ( IF( SUM( IF( ?currency = "CZK" , 1 , 0 ) ) > SUM( IF( ?currency = "EUR" , 1 , 0 ) ) , true , false ) AS ?moreCZK ) WHERE {
  ?cust a <http://debit_card_specializing.org/customers> .
  ?cust <http://debit_card_specializing.org/customers#Segment> "SME" .
  ?cust <http://debit_card_specializing.org/customers#Currency> ?currency .
}

SELECT ?total ?num_above ( ( ?num_above * 100.0 ) / ?total AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?c ) AS ?total ) WHERE {
      ?c <http://debit_card_specializing.org/customers#Segment> ?seg .
      FILTER ( str( ?seg ) = "LAM" )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?c2 ) AS ?num_above ) WHERE {
      ?c2 <http://debit_card_specializing.org/customers#Segment> ?seg2 .
      FILTER ( str( ?seg2 ) = "LAM" ) {
        SELECT ?c2 ( AVG( ?cons ) AS ?avgCons ) WHERE {
          ?ym <http://debit_card_specializing.org/yearmonth#ref-CustomerID> ?c2 .
          ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
        }
        GROUP BY ?c2
      }
      FILTER ( ?avgCons > 46.73 )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( ?over * 100.0 / ?total AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?total ) WHERE {
      ?ym <http://debit_card_specializing.org/yearmonth#Date> "201202" ; <http://debit_card_specializing.org/yearmonth#CustomerID> ?cust .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust2 ) AS ?over ) WHERE {
      ?ym2 <http://debit_card_specializing.org/yearmonth#Date> "201202" ; <http://debit_card_specializing.org/yearmonth#CustomerID> ?cust2 ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
      FILTER ( xsd:decimal ( ?cons ) > 528.3 )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?ym ?date ?cons WHERE {
  ?ym <http://debit_card_specializing.org/yearmonth#Date> ?date .
  ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
  FILTER ( SUBSTR( STR( ?date ) , 1 , 4 ) = "2012" ) {
    SELECT ( MAX( xsd:double ( ?c ) ) AS ?maxCons ) WHERE {
      ?any <http://debit_card_specializing.org/yearmonth#Date> ?d .
      ?any <http://debit_card_specializing.org/yearmonth#Consumption> ?c .
      FILTER ( SUBSTR( STR( ?d ) , 1 , 4 ) = "2012" )
    }
  }
  FILTER ( xsd:double ( ?cons ) = ?maxCons )
}

SELECT DISTINCT ?prod ?description WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Date> ?date .
  FILTER ( SUBSTR( STR( ?date ) , 1 , 7 ) = "2013-09" ) .
  ?tx <http://debit_card_specializing.org/transactions_1k#ProductID> ?prodID .
  ?prod <http://debit_card_specializing.org/products#ProductID> ?prodID .
  OPTIONAL {
    ?prod <http://debit_card_specializing.org/products#Description> ?description
  }
}
ORDER BY ?prod

SELECT DISTINCT ?gasStation ?country WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Date> ?date ; <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gasId .
  ?gasStation <http://debit_card_specializing.org/gasstations#GasStationID> ?gasId ; <http://debit_card_specializing.org/gasstations#Country> ?country .
  FILTER ( STRSTARTS( REPLACE( str( ?date ) , "-" , "" ) , "201306" ) )
}

PREFIX yearmonth: <http://debit_card_specializing.org/yearmonth/>
PREFIX customers: <http://debit_card_specializing.org/customers/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT (COUNT(DISTINCT ?customer) AS ?numCustomers) WHERE {
  ?customer customers:Currency "EUR" .
  ?ym yearmonth:ref-CustomerID ?customer ;
      yearmonth:Consumption ?cons .
  FILTER(xsd:double(?cons) > 1000)
}

SELECT DISTINCT ?productIRI ?description WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gid .
  ?gs <http://debit_card_specializing.org/gasstations#GasStationID> ?gid .
  ?gs <http://debit_card_specializing.org/gasstations#Country> "CZE" .
  ?tx <http://debit_card_specializing.org/transactions_1k#ProductID> ?pid .
  ?productIRI <http://debit_card_specializing.org/products#ProductID> ?pid .
  OPTIONAL {
    ?productIRI <http://debit_card_specializing.org/products#Description> ?description .
  }
}
ORDER BY ?productIRI

SELECT DISTINCT ?time WHERE {
  ?gs <http://debit_card_specializing.org/gasstations#GasStationID> ?gsid ; <http://debit_card_specializing.org/gasstations#ChainID> ?chainID .
  ?trans <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gsid ; <http://debit_card_specializing.org/transactions_1k#Time> ?time .
  FILTER ( str( ?chainID ) = "11" )
}
ORDER BY ?time

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( ?trans ) AS ?count ) WHERE {
  ?trans <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gsid ; <http://debit_card_specializing.org/transactions_1k#Date> ?date .
  ?gas <http://debit_card_specializing.org/gasstations#GasStationID> ?gsid ; <http://debit_card_specializing.org/gasstations#Country> "CZE" .
  FILTER ( xsd:date ( ?date ) > "2012-01-01" ^^ xsd:date )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?customer ?customerLabel ?segment WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Date> "2012-08-23" ; <http://debit_card_specializing.org/transactions_1k#Time> "21:20:00" ; <http://debit_card_specializing.org/transactions_1k#CustomerID> ?custId .
  ?customer <http://debit_card_specializing.org/customers#CustomerID> ?custId .
  OPTIONAL {
    ?customer rdfs:label ?customerLabel .
  }
  OPTIONAL {
    ?customer <http://debit_card_specializing.org/customers#Segment> ?segment .
  }
}

SELECT ?customer ?currency WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Date> "2012-08-24" .
  ?tx <http://debit_card_specializing.org/transactions_1k#Price> ?price .
  ?tx <http://debit_card_specializing.org/transactions_1k#CustomerID> ?custid .
  FILTER ( str( ?price ) = "548.4" ) BIND( IRI( CONCAT ( "http://debit_card_specializing.org/customers/CustomerID=" , STR( ?custid ) ) ) AS ?customer ) OPTIONAL {
    ?customer <http://debit_card_specializing.org/customers#Currency> ?currency
  }
}
LIMIT 10

SELECT ?total ?eur_on_date ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?c ) AS ?total ) WHERE {
      ?c <http://debit_card_specializing.org/customers#CustomerID> ?cid .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?c2 ) AS ?eur_on_date ) WHERE {
      ?t <http://debit_card_specializing.org/transactions_1k#Date> "2012-08-25" .
      ?t <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cid2 .
      ?c2 <http://debit_card_specializing.org/customers#CustomerID> ?cid2 .
      ?c2 <http://debit_card_specializing.org/customers#Currency> "EUR" .
    }
  }
  BIND( ( ?eur_on_date * 100.0 ) / ?total AS ?percentage )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?tx ?cust ?cons2012 ?cons2013 ?diff ?decreaseRate WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Date> ?date ; <http://debit_card_specializing.org/transactions_1k#Price> ?price ; <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cust .
  FILTER ( contains( str( ?date ) , "2012-08-25" ) ) FILTER ( str( ?price ) = "634.8" || contains( str( ?price ) , "634.8" ) ) {
    SELECT ?cust ( SUM( xsd:double ( ?price1 ) ) AS ?cons2012 ) WHERE {
      ?t1 <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cust ; <http://debit_card_specializing.org/transactions_1k#Date> ?date1 ; <http://debit_card_specializing.org/transactions_1k#Price> ?price1 .
      FILTER ( STRSTARTS( STR( ?date1 ) , "2012" ) )
    }
    GROUP BY ?cust
  }
  OPTIONAL {
    SELECT ?cust ( SUM( xsd:double ( ?price2 ) ) AS ?cons2013_raw ) WHERE {
      ?t2 <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cust ; <http://debit_card_specializing.org/transactions_1k#Date> ?date2 ; <http://debit_card_specializing.org/transactions_1k#Price> ?price2 .
      FILTER ( STRSTARTS( STR( ?date2 ) , "2013" ) )
    }
    GROUP BY ?cust
  }
  BIND( COALESCE ( ?cons2013_raw , 0 ) AS ?cons2013 ) BIND( ( ?cons2012 - ?cons2013 ) AS ?diff ) BIND( IF( ?cons2012 = 0 , "NaN" , ( ?diff / ?cons2012 ) ) AS ?decreaseRate )
}
LIMIT 10

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?premiumCount ?totalCount ?percentage WHERE {
  {
    SELECT ( COUNT( ?gsPremium ) AS ?premiumCount ) WHERE {
      ?gsPremium <http://debit_card_specializing.org/gasstations#Country> "SVK" .
      ?gsPremium <http://debit_card_specializing.org/gasstations#Segment> "Premium" .
    }
  }
  {
    SELECT ( COUNT( ?gs ) AS ?totalCount ) WHERE {
      ?gs <http://debit_card_specializing.org/gasstations#Country> "SVK" .
    }
  }
  BIND( IF( ?totalCount > 0 , ( xsd:decimal ( ?premiumCount ) * "100.0" ^^ xsd:decimal ) / xsd:decimal ( ?totalCount ) , 0 ) AS ?percentage )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?customerIRI ?totalAtGas ?ym ?janConsumption WHERE {
  BIND( <http://debit_card_specializing.org/customers/CustomerID=38508> AS ?customerIRI ) OPTIONAL {
    ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> "38508" .
    ?ym <http://debit_card_specializing.org/yearmonth#Date> "201201" .
    ?ym <http://debit_card_specializing.org/yearmonth#Consumption> ?janConsumption .
  }
  {
    SELECT ( SUM( xsd:decimal ( ?amt ) ) AS ?totalAtGas ) WHERE {
      ?tx <http://debit_card_specializing.org/transactions_1k#CustomerID> ?custID .
      FILTER ( str( ?custID ) = "38508" ) ?tx <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gsid .
      ?tx <http://debit_card_specializing.org/transactions_1k#Amount> ?amt .
    }
  }
}
